class XmlPayloadProcessor {

    private static final int LARGE_PAYLOAD_WARNING_THRESHOLD = 5_000;
    private static final int MAX_TEXT_PREVIEW = 256;

    public ProcessingResult processSoapXml(String soapXml,
                                           String sourceSystem,
                                           String importMode,
                                           MessageContext messageContext) throws DataIntegrationFault {
        String requestId = UUID.randomUUID().toString();
        List<String> warnings = new ArrayList<>();
        try {
            SOAPMessage soapMessage = parseSoapMessage(soapXml);
            SOAPBody body = soapMessage.getSOAPBody();
            if (body == null) {
                throw buildFault("INVALID_SOAP", "SOAP Body not found");
            }

            List<EntityRecord> records = new ArrayList<>();
            int totalNodesProcessed = 0;

            NodeList children = body.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                Node node = children.item(i);
                if (node.getNodeType() == Node.ELEMENT_NODE) {
                    Document document = parseDocument(nodeToString(node));
                    EntityRecord rootRecord = traverseAndMap(document.getDocumentElement(), "/" + safeName(document.getDocumentElement()));
                    if (rootRecord != null) {
                        records.add(rootRecord);
                    }
                    totalNodesProcessed += countElements(document.getDocumentElement());
                }
            }

            if (records.isEmpty()) {
                warnings.add("SOAP Body did not contain importable XML entities");
            }

            int importedRecords = flatten(records).size();
            if (importedRecords > LARGE_PAYLOAD_WARNING_THRESHOLD) {
                warnings.add("Large payload detected: " + importedRecords + " entities processed");
            }

            if (sourceSystem == null || sourceSystem.trim().isEmpty()) {
                warnings.add("Source system not provided");
            }

            if (importMode == null || importMode.trim().isEmpty()) {
                warnings.add("Import mode not provided, default processing applied");
            }

            if (messageContext != null) {
                Object httpMethod = messageContext.get(MessageContext.HTTP_REQUEST_METHOD);
                if (httpMethod != null) {
                    warnings.add("Transport method: " + httpMethod);
                }
            }

            ProcessingResult result = new ProcessingResult();
            result.setRequestId(requestId);
            result.setImportedRecords(importedRecords);
            result.setProcessedEntities(records);
            result.setWarnings(warnings);
            result.setTotalNodesProcessed(totalNodesProcessed);
            return result;
        } catch (DataIntegrationFault e) {
            throw e;
        } catch (Exception e) {
            throw buildFault("XML_PROCESSING_ERROR", e.getMessage());
        }
    }

    private SOAPMessage parseSoapMessage(String soapXml) throws SOAPException {
        MessageFactory messageFactory = MessageFactory.newInstance(SOAPConstants.SOAP_1_1_PROTOCOL);
        MimeHeaders headers = new MimeHeaders();
        headers.addHeader("Content-Type", "text/xml; charset=UTF-8");
        InputStream inputStream = new ByteArrayInputStream(soapXml.getBytes(StandardCharsets.UTF_8));
        return messageFactory.createMessage(headers, inputStream);
    }

    private Document parseDocument(String xml) throws ParserConfigurationException, IOExceptionEx, SAXException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        secureFactory(factory);
        DocumentBuilder builder = factory.newDocumentBuilder();
        try (Reader reader = new StringReader(xml)) {
            return builder.parse(new InputSource(reader));
        } catch (java.io.IOException e) {
            throw new IOExceptionEx(e);
        }
    }

    private void secureFactory(DocumentBuilderFactory factory) throws ParserConfigurationException {
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setExpandEntityReferences(false);
        factory.setXIncludeAware(false);
    }

    private EntityRecord traverseAndMap(Element root, String path) {
        EntityRecord record = new EntityRecord();
        record.setName(safeName(root));
        record.setPath(path);
        record.setAttributes(extractAttributes(root));
        record.setText(extractText(root));

        List<EntityRecord> children = new ArrayList<>();
        NodeList nodeList = root.getChildNodes();
        for (int i = 0; i < nodeList.getLength(); i++) {
            Node child = nodeList.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;
                children.add(traverseAndMap(childElement, path + "/" + safeName(childElement)));
            }
        }
        record.setChildren(children);
        return record;
    }

    private Map<String, String> extractAttributes(Element element) {
        NamedNodeMap namedNodeMap = element.getAttributes();
        if (namedNodeMap == null || namedNodeMap.getLength() == 0) {
            return Collections.emptyMap();
        }
        Map<String, String> attributes = new LinkedHashMap<>();
        for (int i = 0; i < namedNodeMap.getLength(); i++) {
            Node attribute = namedNodeMap.item(i);
            attributes.put(attribute.getNodeName(), attribute.getNodeValue());
        }
        return attributes;
    }

    private String extractText(Element element) {
        StringBuilder text = new StringBuilder();
        NodeList nodeList = element.getChildNodes();
        for (int i = 0; i < nodeList.getLength(); i++) {
            Node child = nodeList.item(i);
            if (child.getNodeType() == Node.TEXT_NODE || child.getNodeType() == Node.CDATA_SECTION_NODE) {
                String value = child.getNodeValue();
                if (value != null) {
                    String trimmed = value.trim();
                    if (!trimmed.isEmpty()) {
                        if (text.length() > 0) {
                            text.append(' ');
                        }
                        text.append(trimmed);
                    }
                }
            }
        }
        String result = text.toString();
        return result.length() > MAX_TEXT_PREVIEW ? result.substring(0, MAX_TEXT_PREVIEW) : result;
    }

    private int countElements(Element root) {
        int count = 0;
        Deque<Node> stack = new ArrayDeque<>();
        stack.push(root);
        while (!stack.isEmpty()) {
            Node current = stack.pop();
            if (current.getNodeType() == Node.ELEMENT_NODE) {
                count++;
            }
            NodeList children = current.getChildNodes();
            for (int i = children.getLength() - 1; i >= 0; i--) {
                Node child = children.item(i);
                if (child.getNodeType() == Node.ELEMENT_NODE) {
                    stack.push(child);
                }
            }
        }
        return count;
    }

    private List<EntityRecord> flatten(List<EntityRecord> roots) {
        List<EntityRecord> all = new ArrayList<>();
        Deque<EntityRecord> stack = new ArrayDeque<>(roots);
        while (!stack.isEmpty()) {
            EntityRecord record = stack.pop();
            all.add(record);
            List<EntityRecord> children = record.getChildren();
            if (children != null) {
                for (int i = children.size() - 1; i >= 0; i--) {
                    stack.push(children.get(i));
                }
            }
        }
        return all;
    }

    private String safeName(Node node) {
        return node.getLocalName() != null ? node.getLocalName() : node.getNodeName();
    }

    private String nodeToString(Node node) {
        StringBuilder builder = new StringBuilder();
        serializeNode(node, builder);
        return builder.toString();
    }

    private void serializeNode(Node node, StringBuilder builder) {
        switch (node.getNodeType()) {
            case Node.ELEMENT_NODE:
                builder.append("<").append(node.getNodeName());
                NamedNodeMap attributes = node.getAttributes();
                if (attributes != null) {
                    for (int i = 0; i < attributes.getLength(); i++) {
                        Node attr = attributes.item(i);
                        builder.append(" ")
                               .append(attr.getNodeName())
                               .append("=\"")
                               .append(escape(attr.getNodeValue()))
                               .append("\"");
                    }
                }
                NodeList children = node.getChildNodes();
                if (children.getLength() == 0) {
                    builder.append("/>");
                } else {
                    builder.append(">");
                    for (int i = 0; i < children.getLength(); i++) {
                        serializeNode(children.item(i), builder);
                    }
                    builder.append("</").append(node.getNodeName()).append(">");
                }
                break;
            case Node.TEXT_NODE:
                builder.append(escape(node.getNodeValue()));
                break;
            case Node.CDATA_SECTION_NODE:
                builder.append("<![CDATA[").append(node.getNodeValue()).append("]]>");
                break;
            default:
                break;
        }
    }

    private String escape(String value) {
        if (value == null) {
            return "";
        }
        return value.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&apos;");
    }

    private DataIntegrationFault buildFault(String code, String message) {
        FaultDetail detail = new FaultDetail();
        detail.setCode(code);
        detail.setMessage(message);
        detail.setTimestamp(OffsetDateTime.now().toString());
        return new DataIntegrationFault(message, detail);
    }
}

